Code.Terraform:
```hcl
resource "aws_waf_web_acl" "<example_resource_name>" {
  name        = "<example_resource_name>"
  metric_name = "<example_metric_name>"

  default_action {
    type = "ALLOW"
  }

  rules { # 关键：至少添加一条规则，以使 Web ACL 不为空
    priority = 1
    rule_id  = "<example_rule_id>"
    type     = "REGULAR"
    action {
      type = "BLOCK"
    }
  }
}
```
